import api from "./api";

export const obtenerUsuarios = async () => {
  const respuesta = await api.get("/users");
  return respuesta.data;
};

export const ascenderUsuario = async (id) => {
  const respuesta = await api.put(`/users/${id}/promote`);
  return respuesta.data;
};

export const degradarUsuario = async (id) => {
  const respuesta = await api.put(`/users/${id}/demote`);
  return respuesta.data;
};
